let extrusionPaths = '';
const steps = 30;
const maxDx = 1.2;
const maxDy = 2.4;
for (let i = steps; i >= 1; i--) {
    const t = i / steps;
    const fill = t > 0.8 ? "url(#left-cut-grad)" : (t > 0.2 ? "url(#left-cut-grad)" : "url(#left-bevel-grad)");
    extrusionPaths += `        <path d="${pathData}" fill="${fill}" transform="translate(${maxDx * t}, ${maxDy * t})" />\n`;
}

extrusionPaths += `        <path d="${pathData}" fill="url(#left-bevel-grad)" transform="translate(0.1, 0.2)" />\n`;
extrusionPaths += `        <path d="${pathData}" fill="url(#left-bevel-grad)" transform="translate(-0.1, -0.2)" />\n`;

